from pathlib import Path

path = Path(r'c:\Users\32328\Desktop\zhiXiShuXue\backend\routes\student.js')
text = path.read_text(encoding='utf-8')
old = "function getPracticeQuestionsFromDatabase(knowledgePoint, masteryRate) {\n  if (!knowledgePoint) return [];\n\n  const level = getPracticeDifficulty(masteryRate);\n\n  return db.find('questions')\n    .filter(question => {\n      return Array.isArray(question.knowledgePoints) && question.knowledgePoints.includes(knowledgePoint.id);\n    })\n    .filter(question => question.source === 'practice-seed')\n    .filter(question => !question.difficulty || question.difficulty === level)\n    .map(question => ({\n      ...question,\n      answerDisplay: question.type === 'choice'\n        ? buildChoiceDisplay(question, question.answer)\n        : (question.answer || '-')\n    }));\n}\n"
new = "function getPracticeQuestionsFromDatabase(knowledgePoint, masteryRate) {\n  if (!knowledgePoint) return [];\n\n  const level = getPracticeDifficulty(masteryRate);\n  const levelOrder = level === 'easy' ? ['easy', 'medium', 'hard'] : (level === 'medium' ? ['medium', 'easy', 'hard'] : ['hard', 'medium', 'easy']);\n\n  const allQuestions = db.find('questions')\n    .filter(question => {\n      return Array.isArray(question.knowledgePoints) && question.knowledgePoints.includes(knowledgePoint.id);\n    })\n    .filter(question => question.source === 'practice-seed');\n\n  const matched = [];\n  levelOrder.forEach(currentLevel => {\n    allQuestions\n      .filter(question => (question.difficulty || 'easy') === currentLevel)\n      .forEach(question => matched.push(question));\n  });\n\n  const fallbackQuestions = matched.length ? matched : allQuestions;\n\n  return fallbackQuestions.map(question => ({\n    ...question,\n    answerDisplay: question.type === 'choice'\n      ? buildChoiceDisplay(question, question.answer)\n      : (question.answer || '-')\n  }));\n}\n"
text = text.replace(old, new)
path.write_text(text, encoding='utf-8')
